// 전월 연월 계산 (매월 1일 실행 → 전월 리포트)
const now = new Date();
const prevMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const year = prevMonth.getFullYear();
const month = String(prevMonth.getMonth() + 1).padStart(2, '0');
const yearMonth = year + '-' + month;

// 한국어 월명
const monthNames = ['1월','2월','3월','4월','5월','6월','7월','8월','9월','10월','11월','12월'];
const monthLabel = year + '년 ' + monthNames[prevMonth.getMonth()];

return [{ json: { yearMonth, monthLabel, year, month: parseInt(month) } }];

const input = $input.first().json;
const calcMonth = $('전월 계산').first().json;

if (!input.ok || !input.staffSummaries) {
  return [{ json: { error: true, message: '월간 요약 데이터 없음' } }];
}

const summaries = input.staffSummaries;

// === 1. 텔레그램 요약 메시지 생성 ===
let msg = '\ud83d\udcca ' + calcMonth.monthLabel + ' \uadfc\ud0dc \ub9ac\ud3ec\ud2b8\n\n';

let totalAttended = 0;
let totalWork = 0;
let staffCount = summaries.length;

for (const s of summaries) {
  const statusIcon = s.attendedDays === s.totalWorkDays ? '\u2705' : '\u26a0\ufe0f';
  const avgHours = s.avgWorkMinutes > 0 ? (s.avgWorkMinutes / 60).toFixed(1) + 'h' : '-';
  const workTypeLabel = s.workType === 'deemed_hours' ? ' (\uac04\uc8fc)' : '';

  msg += statusIcon + ' ' + s.staffName + workTypeLabel + '\n';
  msg += '   \ucd9c\uadfc ' + s.attendedDays + '/' + s.totalWorkDays + '\uc77c';
  if (s.workType !== 'deemed_hours' && s.avgWorkMinutes > 0) {
    msg += ' | \ud3c9\uade0 ' + avgHours;
  }
  msg += '\n';
  if (s.remoteDays > 0) msg += '   \uc7ac\ud0dd ' + s.remoteDays + '\uc77c';
  if (s.fieldDays > 0) msg += ' | \uc678\uadfc ' + s.fieldDays + '\uc77c';
  if (s.remoteDays > 0 || s.fieldDays > 0) msg += '\n';
  msg += '\n';

  totalAttended += s.attendedDays;
  totalWork += s.totalWorkDays;
}

msg += '\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n';
msg += '\uc804\uccb4 \ucd9c\uadfc\uc728: ' + (totalWork > 0 ? Math.round(totalAttended / totalWork * 100) : 0) + '%\n';
msg += '\uc694\uc57d: ' + staffCount + '\uba85 | ' + totalAttended + '/' + totalWork + '\uc77c';

// === 2. CSV 바이너리 생성 ===
let csv = '\uc774\ub984,\uc77c\uc790,\ucd9c\uadfc\uc2dc\uac01,\ud1f4\uadfc\uc2dc\uac01,\uadfc\ubb34\ud615\ud0dc,\uadfc\ubb34\uc2dc\uac04(\ubd84),\ube44\uace0\n';

for (const s of summaries) {
  if (!s.dailyRecords) continue;
  for (const day of s.dailyRecords) {
    const note = s.workType === 'deemed_hours' ? '\uac04\uc8fc\uadfc\ub85c \uc2dc\uac04\uacc4\uc0b0\uc81c\uc678' : '';
    const workModeKr = day.workMode === 'office' ? '\uc0ac\uc5c5\uc7a5' : day.workMode === 'remote' ? '\uc7ac\ud0dd' : '\uc678\uadfc';
    csv += s.staffName + ',' + day.date + ',' + (day.clockIn || '') + ',' + (day.clockOut || '') + ',' + workModeKr + ',' + (day.workMinutes || '') + ',' + note + '\n';
  }
}

const csvBuffer = Buffer.from(csv, 'utf-8');
const fileName = 'HR_\uadfc\ud0dc\ub9ac\ud3ec\ud2b8_' + calcMonth.yearMonth + '.csv';

return [{
  json: {
    message: msg,
    fileName: fileName,
    yearMonth: calcMonth.yearMonth,
    staffCount: staffCount,
    totalAttended: totalAttended,
    totalWork: totalWork
  },
  binary: {
    data: {
      data: csvBuffer.toString('base64'),
      mimeType: 'text/csv',
      fileName: fileName
    }
  }
}];
